"import 'dart:io';
import 'dart:convert';

void main() {
  final logFile = File(r'C:\Users\psiva\.gemini\antigravity\brain\8edb297c-47eb-4d17-8a72-1e7dda5dee70\.system_generated\logs\transcript.jsonl');
  final lines = logFile.readAsLinesSync();

  // Look for the last successful view_file or tool call containing player_screen.dart with valid content
  for (int i = lines.length - 1; i >= 0; i--) {
    if (lines[i].contains('PlayerScreen extends StatefulWidget')) {
      // It might be a replace_file_content diff or something else.
      // Let's print the step type and context.
      try {
        final Map<String, dynamic> step = jsonDecode(lines[i]);
        if (step['type'] == 'TOOL_CALL' || step['type'] == 'TOOL_RESPONSE' || step['type'] == 'PLANNER_RESPONSE') {
          // print("Found at line \$i: \${step['type']}");
          // Check if it has the full file content.
          String content = lines[i];
          if (content.contains('class PlayerScreen') && content.contains('class _PlayerScreenState')) {
            print("Found potential full file at log line \$i");
            // Just write this raw log line to a file so we can inspect it
            File('found_log.json').writeAsStringSync(lines[i]);
            break;
          }
        }
      } catch (e) {
        // ignore
      }
    }
  }
}
